// Smoke Machine -- layered noise, heavy feedback, slow hue drift
speed = 0.5

AUDIO.bins = 6; AUDIO.smooth = 0.80; AUDIO.gain = 30; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.4, 0.03);
var mid  = env(_mi, 0.35, 0.04);
var high = env(_hi, 0.3, 0.05);
var amp  = function(){ return (low() + mid() + high()) * 0.7 };

noise(2, 0.08)
  .color(
    () => 0.85 + low() * 0.5,
    () => 0.5 + mid() * 0.4,
    () => 0.7 + high() * 0.4
  )
  .modulate(noise(1.2, 0.04), () => 0.15 + low() * 0.01)
  .modulate(noise(4, 0.12), () => 0.04 + mid() * 0.005)
  .blend(
    osc(6, 0.02, 2.5)
      .color(
        () => 0.6 + mid() * 0.3,
        () => 0.4 + high() * 0.4,
        () => 0.9 + low() * 0.3
      )
      .modulate(noise(3, 0.06), 0.08),
    0.2
  )
  .blend(src(o0).rotate(() => Math.sin(time * 0.015) * 0.002).hue(() => time * 0.002 + amp() * 0.006), 0.88)
  .saturate(() => 1.15 + low() * 0.3)
  .colorama(() => 0.001 + amp() * 0.002)
  .hue(() => Math.sin(time * 0.03) * 0.03)
  .contrast(() => 1.02 + low() * 0.05)
  .brightness(0.04)
  .out(o0)
